# Find hadiths with tokens containing 'المؤمن' and 'الدنيا' and 'الاخرة'
needle_tokens = ['المؤمن', 'الدنيا', 'الاخرة']
hits = []
for i, rec in enumerate(hjson):
    for field in ('Matn','hadithTxt'):
        txt = rec.get(field)
        if not txt:
            continue
        norm = normalize_ar2(txt)
        tokens = norm.split()
        if all(tok in tokens for tok in needle_tokens):
            # compute positions
            pos = {tok: [idx for idx,t in enumerate(tokens) if t==tok] for tok in needle_tokens}
            # compute min span covering tokens
            min_span = None
            for a in pos[needle_tokens[0]]:
                for b in pos[needle_tokens[1]]:
                    for c in pos[needle_tokens[2]]:
                        span = max(a,b,c)-min(a,b,c)
                        if min_span is None or span<min_span:
                            min_span = span
            hits.append((i, field, min_span, txt))
# sort by small span
hits_sorted = sorted(hits, key=lambda x: x[2])
len(hits_sorted), hits_sorted[:30]

